sys_ui_script.script:
/**
 * Global UI Script
 * Name: NowAssistPanelMessageAutoExpand
 *
 * Goal:
 * - If the Now Assist panel is open, force all rich-text messages to be expanded.
 * - Hide the "Show more" / "Show less" controls.
 *
 * Notes:
 * - This runs from forms/UI Pages (typically inside an iframe like gsft_main).
 * - The Now Assist panel lives in the shell (window.top). We therefore operate on window.top
 *   and store the observer/state on window.top to ensure it keeps working as content updates.
 * - Uses deep querying into OPEN shadow roots (as shown in your screenshots).
 */
function NowAssistPanelMessageAutoExpand()
{
  var shellWin = window;
  try {
    if (window.top && window.top.document) shellWin = window.top;
  } catch (e) {
    shellWin = window; // fallback if top is not accessible
  }

  // Install once (store state on the shell window).
  if (shellWin.__nowAssistAutoExpand && shellWin.__nowAssistAutoExpand.installed) {
    shellWin.__nowAssistAutoExpand.runOnce();
    return;
  }

  shellWin.__nowAssistAutoExpand = (function (w) {
    var state = {
      installed: true,
      scheduled: false,
      roots: null,
      observer: null,
      observedShadowRoots: w.WeakSet ? new w.WeakSet() : null,
      observedShadowRootsArr: [] // fallback if WeakSet not available
    };

    function isObservedShadowRoot(sr) {
      if (!sr) return true;
      if (state.observedShadowRoots) return state.observedShadowRoots.has(sr);
      for (var i = 0; i < state.observedShadowRootsArr.length; i++) {
        if (state.observedShadowRootsArr[i] === sr) return true;
      }
      return false;
    }

    function markObservedShadowRoot(sr) {
      if (!sr) return;
      if (state.observedShadowRoots) state.observedShadowRoots.add(sr);
      else state.observedShadowRootsArr.push(sr);
    }

    // Throttle re-application to avoid excessive DOM work
    function schedule() {
      if (state.scheduled) return;
      state.scheduled = true;
      w.setTimeout(function () {
        state.scheduled = false;
        runOnce();
      }, 50);
    }

    /**
     * Recursively query selector across light DOM + OPEN shadow roots.
     * Returns a flat array of matching elements.
     */
    function queryAllDeep(root, selector) {
      var results = [];
      if (!root) return results;

      function scan(node) {
        if (!node) return;

        // 1) Collect matches in this root
        try {
          var found = node.querySelectorAll(selector);
          for (var i = 0; i < found.length; i++) results.push(found[i]);
        } catch (e) {}

        // 2) Traverse elements to enter open shadow roots
        var all = [];
        try {
          all = node.querySelectorAll("*");
        } catch (e2) {
          all = [];
        }

        for (var j = 0; j < all.length; j++) {
          var el = all[j];
          if (el && el.shadowRoot) scan(el.shadowRoot);
        }
      }

      scan(root);
      return results;
    }

    /**
     * Try to find a smaller "search root" for the Now Assist panel rather than scanning the whole page.
     * Falls back to the full document if unknown.
     */
    function discoverRoots(doc) {
      var roots = [];

      // Common/likely hosts (harmless if none exist)
      var hostSelectors =
        "sn-cs-control-chat, sn-cs-control-chat-container, sn-now-assist, sn-now-assist-panel, sn-assist-panel, now-assist, now-assist-panel";

      try {
        var hosts = doc.querySelectorAll(hostSelectors);
        for (var i = 0; i < hosts.length; i++) {
          if (hosts[i] && hosts[i].shadowRoot) roots.push(hosts[i].shadowRoot);
        }
      } catch (e) {}

      // Heuristic fallback: find any element with an open shadowRoot containing the target classes
      if (!roots.length) {
        try {
          var all = doc.querySelectorAll("*");
          for (var j = 0; j < all.length; j++) {
            var el = all[j];
            if (!el || !el.shadowRoot) continue;

            var sr = el.shadowRoot;
            try {
              if (
                sr.querySelector(".sn-cs-rich-text-height-wrapper") ||
                sr.querySelector(".sn-cs-rich-text-container") ||
                sr.querySelector(".now-button-bar-label") ||
                sr.querySelector("now-button-bar")
              ) {
                roots.push(sr);
                // keep scanning a bit more is expensive; one good root is usually enough
                break;
              }
            } catch (e2) {}
          }
        } catch (e3) {}
      }

      return roots.length ? roots : [doc];
    }

    function forceExpandedMessage(el) {
      if (!el || !el.style) return;
      // The key fix from your observation: block -> flex for correct expansion,
      // plus ensure no max-height/overflow clipping remains.
      try {
        el.style.setProperty("display", "flex", "important");
        el.style.setProperty("max-height", "none", "important");
        el.style.setProperty("height", "auto", "important");
        el.style.setProperty("overflow", "visible", "important");
        el.style.setProperty("-webkit-line-clamp", "unset", "important");
      } catch (e) {}
      try {
        if (el.classList && !el.classList.contains("nowassist-autoexpanded"))
          el.classList.add("nowassist-autoexpanded");
      } catch (e2) {}
    }

    function hideShowMoreLessFromLabel(labelEl) {
      if (!labelEl) return;

      var t = "";
      try {
        t = (labelEl.textContent || "").replace(/\s+/g, " ").trim().toLowerCase();
      } catch (e) {}

      if (t !== "show more" && t !== "show less") return;

      // Prefer hiding the <now-button-bar> host; fallback to button container
      var toHide = null;
      try {
        if (labelEl.closest) {
          toHide = labelEl.closest("now-button-bar") || labelEl.closest("button") || labelEl.closest(".now-button-bar");
        }
      } catch (e2) {}

      if (!toHide) {
        // last resort: walk up a few levels
        toHide = labelEl.parentNode && labelEl.parentNode.parentNode ? labelEl.parentNode.parentNode : labelEl.parentNode;
      }

      if (toHide && toHide.style) {
        try {
          toHide.style.setProperty("display", "none", "important");
          toHide.setAttribute("aria-hidden", "true");
        } catch (e3) {}
      }
    }

    function applyToRoot(root) {
      // Expand both wrapper and container (matches your screenshot structure)
      var wrappers = queryAllDeep(root, ".sn-cs-rich-text-height-wrapper.truncateable.expandable");
      for (var i = 0; i < wrappers.length; i++) forceExpandedMessage(wrappers[i]);

      var containers = queryAllDeep(root, ".sn-cs-rich-text-container");
      for (var j = 0; j < containers.length; j++) forceExpandedMessage(containers[j]);

      // Hide "Show more"/"Show less"
      var labels = queryAllDeep(root, ".now-button-bar-label");
      for (var k = 0; k < labels.length; k++) hideShowMoreLessFromLabel(labels[k]);
    }

    // Observe open shadow roots where the chat content lives, otherwise updates inside shadow DOM won’t trigger.
    function observeShadowRoots(root) {
      var shadowHosts = queryAllDeep(root, "*"); // we already traverse; use results to find shadowRoots
      for (var i = 0; i < shadowHosts.length; i++) {
        var el = shadowHosts[i];
        if (!el || !el.shadowRoot) continue;

        var sr = el.shadowRoot;
        if (isObservedShadowRoot(sr)) continue;

        // Only observe shadow roots that look relevant (avoid observing the whole world)
        try {
          if (
            sr.querySelector(".sn-cs-rich-text-height-wrapper") ||
            sr.querySelector(".sn-cs-rich-text-container") ||
            sr.querySelector(".now-button-bar-label") ||
            sr.querySelector("now-button-bar")
          ) {
            markObservedShadowRoot(sr);

            var mo = new w.MutationObserver(function () {
              schedule();
            });
            mo.observe(sr, { childList: true, subtree: true, attributes: true });
          }
        } catch (e) {}
      }
    }

    function runOnce() {
      var doc = w.document;
      if (!doc) return;

      // Discover or re-discover likely roots (panel can open/close)
      if (!state.roots || !state.roots.length) state.roots = discoverRoots(doc);

      // Apply expansion/hide controls
      for (var i = 0; i < state.roots.length; i++) {
        applyToRoot(state.roots[i]);
        observeShadowRoots(state.roots[i]);
      }
    }

    function installObserver() {
      if (state.observer) return;

      try {
        state.observer = new w.MutationObserver(function () {
          // Panel open/close and host changes happen in light DOM
          // (and we separately observe relevant shadow roots once discovered)
          schedule();
        });

        var target = w.document.documentElement || w.document.body;
        if (target) {
          state.observer.observe(target, {
            childList: true,
            subtree: true,
            attributes: true,
            attributeFilter: ["class", "style", "hidden", "aria-expanded"]
          });
        }
      } catch (e) {}
    }

    installObserver();
    // initial run (and will keep enforcing via observers)
    schedule();

    return {
      installed: true,
      runOnce: runOnce
    };
  })(shellWin);

  shellWin.__nowAssistAutoExpand.runOnce();
}
